// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {

  const getWeatherIcon = useCallback((condition: string) => {
    const c = (condition || '').toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return 'sun';
    if (c.includes('cloud')) return 'cloud';
    if (c.includes('rain') || c.includes('drizzle')) return 'cloud-rain';
    if (c.includes('snow')) return 'cloud-snow';
    if (c.includes('thunder')) return 'cloud-lightning';
    if (c.includes('wind')) return 'wind';
    return 'sun';
  }, []);

  return {
    getWeatherIcon,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-4)">
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="xl" border>
        <Stack gap="var(--ggui-spacing-6)">
          {/* Header Section */}
          <Stack direction="horizontal" justify="between" align="start">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Current Conditions</Text>
            </Stack>
            <Tooltip content="Live weather update">
              <Icon name="rss" size={20} color="var(--ggui-color-primary-500)" />
            </Tooltip>
          </Stack>

          {/* Main Weather Display */}
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
                {props.temperature}°{props.unit}
              </Text>
              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
            </Stack>
            <Icon name={state.getWeatherIcon(props.condition)} size={72} color="var(--ggui-color-primary-500)" />
          </Stack>

          {/* Key Metrics */}
          <Card variant="secondary" padding="var(--ggui-spacing-4)" radius="lg" border={false} style={{ background: 'var(--ggui-color-surfaceVariant)' }}>
            <Stack direction="horizontal" justify="around" align="center">
              <Stack align="center" gap="var(--ggui-spacing-2)">
                <Icon name="droplets" size={20} color="var(--ggui-color-info-500)" />
                <Stack align="center" gap={0}>
                  <Text variant="label" size="xs">Humidity</Text>
                  <Text weight="semibold">{props.humidity}%</Text>
                </Stack>
              </Stack>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />
              <Stack align="center" gap="var(--ggui-spacing-2)">
                <Icon name="wind" size={20} color="var(--ggui-color-primary-400)" />
                <Stack align="center" gap={0}>
                  <Text variant="label" size="xs">Wind</Text>
                  <Text weight="semibold">{props.windSpeed} km/h</Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>

          {/* Forecast Strip */}
          <Stack gap="var(--ggui-spacing-4)">
            <Divider />
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">5-Day Forecast</Text>
            <Stack direction="horizontal" justify="between" align="center" wrap>
              {props.forecast?.map((f, i) => (
                <Stack key={i} align="center" gap="var(--ggui-spacing-2)" style={{ flex: 1, minWidth: '60px' }}>
                  <Text variant="bodySmall" weight="medium">{f.day}</Text>
                  <Icon name={state.getWeatherIcon(f.icon || '')} size={24} color="var(--ggui-color-onSurfaceVariant)" />
                  <Stack direction="horizontal" gap="var(--ggui-spacing-1)">
                    <Text variant="caption" weight="bold">{f.high}°{props.unit}</Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{f.low}°{props.unit}</Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Stack>
