}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<ActionSubmitPayload>({
    name: '',
    email: '',
    satisfaction: 0,
    features: [],
    comments: ''
  });
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const totalSteps = 5; // 4 data steps + 1 review step

  const isEmailValid = useCallback((email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }, []);

  const getFieldError = useCallback((field: string) => {
    if (!touched[field]) return '';
    if (field === 'name' && !formData.name.trim()) return 'Name is required';
    if (field === 'email') {
      if (!formData.email.trim()) return 'Email is required';
      if (!isEmailValid(formData.email)) return 'Invalid email format';
    }
    return '';
  }, [formData, touched, isEmailValid]);

  const canGoNext = useCallback(() => {
    if (currentStep === 1) return formData.name.trim().length > 0 && isEmailValid(formData.email);
    if (currentStep === 2) return formData.satisfaction > 0;
    if (currentStep === 3) return true; // Features are optional
    if (currentStep === 4) return formData.comments.length <= 500;
    return true;
  }, [currentStep, formData, isEmailValid]);

  const handleNext = useCallback(() => {
    if (canGoNext()) {
      setCurrentStep(prev => Math.min(prev + 1, totalSteps));
    } else {
      // Mark current fields as touched to show validation on "Next" click
      if (currentStep === 1) setTouched({ name: true, email: true });
    }
  }, [canGoNext, currentStep]);

  const handleBack = useCallback(() => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  }, []);

  const updateField = useCallback((field: keyof ActionSubmitPayload, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (!touched[field]) setTouched(prev => ({ ...prev, [field]: true }));
  }, [touched]);

  const toggleFeature = useCallback((feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  }, []);

  const handleSubmit = useCallback(() => {
    submit(formData);
  }, [formData, submit]);

  return { 
    currentStep,
    totalSteps,
    formData,
    getFieldError,
    canGoNext,
    handleNext,
    handleBack,
    updateField,
    toggleFeature,
    handleSubmit,
    submit,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const {
    currentStep,
    totalSteps,
    formData,
    getFieldError,
    canGoNext,
    handleNext,
    handleBack,
    updateField,
    toggleFeature,
    handleSubmit,
  } = state;

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-8) 0">
      <Stack gap={24}>
        {/* Progress Section */}
        <Stack gap={8}>
          <Row justify="between" align="center">
            <Heading level={4}>Survey</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of {totalSteps}
            </Text>
          </Row>
          <Progress value={currentStep} max={totalSteps} variant="default" size="sm" />
        </Stack>

        <Card padding={24} shadow="md">
          <Stack gap={24}>
            {/* Step 1: Identity */}
            {currentStep === 1 && (
              <Stack gap={16}>
                <Heading level={3}>Tell us about yourself</Heading>
                <Input
                  label="Full Name"
                  required
                  value={formData.name}
                  onChange={(v) => updateField('name', v)}
                  error={getFieldError('name')}
                  placeholder="Jane Doe"
                />
                <Input
                  label="Email Address"
                  type="email"
                  required
                  value={formData.email}
                  onChange={(v) => updateField('email', v)}
                  error={getFieldError('email')}
                  placeholder="jane@example.com"
                />
              </Stack>
            )}

            {/* Step 2: Satisfaction */}
            {currentStep === 2 && (
              <Stack gap={16}>
                <Heading level={3}>Overall Satisfaction</Heading>
                <RadioGroup
                  label="How satisfied are you with our service?"
                  value={String(formData.satisfaction)}
                  onChange={(v) => updateField('satisfaction', Number(v))}
                  options={(props.satisfactionLabels || []).map((label, i) => ({
                    value: String(i + 1),
                    label: label,
                  }))}
                />
              </Stack>
            )}

            {/* Step 3: Features */}
            {currentStep === 3 && (
              <Stack gap={16}>
                <Heading level={3}>Feature Interest</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Select all features that interest you.
                </Text>
                <Stack gap={12}>
                  {(props.featureOptions || []).map(option => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={formData.features.includes(option)}
                      onChange={() => toggleFeature(option)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {/* Step 4: Comments */}
            {currentStep === 4 && (
              <Stack gap={16}>
                <Heading level={3}>Any final thoughts?</Heading>
                <TextArea
                  label="Comments (Optional)"
                  value={formData.comments}
                  onChange={(v) => updateField('comments', v)}
                  maxLength={500}
                  showCount
                  rows={6}
                  placeholder="Tell us what's on your mind..."
                />
              </Stack>
            )}

            {/* Step 5: Review */}
            {currentStep === 5 && (
              <Stack gap={16}>
                <Heading level={3}>Review your answers</Heading>
                <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
                  <Stack gap={12}>
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Identity</Text>
                      <Text variant="body">{formData.name} • {formData.email}</Text>
                    </Box>
                    <Divider margin={8} />
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                  <Text variant="body">{props.satisfactionLabels?.[formData.satisfaction - 1] || 'No rating'}</Text>
                    </Box>
                    <Divider margin={8} />
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Interested Features</Text>
                      <Text variant="body">{formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}</Text>
                    </Box>
                    <Divider margin={8} />
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                      <Text variant="body">{formData.comments || 'No comments provided'}</Text>
                    </Box>
                  </Stack>
                </Box>
              </Stack>
            )}

            {/* Navigation Buttons */}
            <Row gap={12} justify="end">
              {currentStep > 1 && (
                <Button variant="outline" onClick={handleBack}>Back</Button>
              )}
              {currentStep < totalSteps ? (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext()}>
                  Next Step
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

