import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);

  const categoryColors: Record<string, { bg: string; text: string }> = useMemo(() => ({
    'alkali metal': { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-700, #b91c1c)' },
    'alkaline earth metal': { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-700, #b45309)' },
    'transition metal': { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-700, #0369a1)' },
    'post-transition metal': { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-700, #15803d)' },
    'metalloid': { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-700, #0e7490)' },
    'reactive nonmetal': { bg: 'var(--ggui-color-warning-200, #fde68a)', text: 'var(--ggui-color-warning-800, #92400e)' },
    'noble gas': { bg: 'var(--ggui-color-container, #ede9fe)', text: 'var(--ggui-color-onContainer, #4c1d95)' },
    'lanthanide': { bg: 'var(--ggui-color-primary-200, #bae6fd)', text: 'var(--ggui-color-primary-800, #075985)' },
    'actinide': { bg: 'var(--ggui-color-outlineVariant, #e4e4e7)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)' },
    'unknown': { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurfaceVariant, #52525b)' },
  }), []);

  const getCategoryStyle = useCallback((category?: string) => {
    const cat = category?.toLowerCase() || 'unknown';
    return categoryColors[cat] || categoryColors['unknown'];
  }, [categoryColors]);

  const filteredElements = useMemo(() => {
    const elements = props.elements || [];
    if (!searchTerm) return elements;
    const lowerSearch = searchTerm.toLowerCase();
    return elements.filter(el => (
      el.name?.toLowerCase()?.includes(lowerSearch) || 

      el.symbol?.toLowerCase()?.includes(lowerSearch)
    ));
  }, [props.elements, searchTerm]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    (props.elements || []).forEach(el => { if (el.category) set.add(el.category); });
    return Array.from(set);
  }, [props.elements]);

  return {
    searchTerm,
    setSearchTerm,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryStyle,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Heading level={1} align="center">Periodic Table of Elements</Heading>
          <SearchField
            value={state.searchTerm}
            onChange={state.setSearchTerm}
            placeholder="Search by name or symbol (e.g. Gold, Au)..."
            size="lg"
          />
        </Stack>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <Box style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))', 
            gridAutoRows: 'minmax(80px, auto)',
            gap: 'var(--ggui-spacing-1, 4px)',
            minWidth: '1100px',
          }}>
            {(state.filteredElements || []).map((el) => {
              const styles = state.getCategoryStyle(el.category);
              const isSelected = state.selectedElement?.atomicNumber === el.atomicNumber;
              return (
                <Card
                  key={el.atomicNumber}
                  as={Clickable}
                  onClick={() => state.setSelectedElement(el)}
                  padding="var(--ggui-spacing-2, 8px)"
                  shadow={isSelected ? 'lg' : 'sm'}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    backgroundColor: styles.bg,
                    border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    position: 'relative',
                    height: '80px',
                    transition: 'all 0.2s ease',
                  }}
                >
                  <Box style={{ position: 'absolute', top: '4px', left: '4px' }}>
                    <Text variant="caption" color={styles.text} weight="bold">{el.atomicNumber}</Text>
                  </Box>
                  <Stack align="center" justify="center" style={{ height: '100%' }}>
                    <Heading level={4} color={styles.text}>{el.symbol}</Heading>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        </Box>

        <Card padding="var(--ggui-spacing-4, 16px)" radius="lg" shadow="md">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Heading level={4}>Element Categories</Heading>
            <Row gap="var(--ggui-spacing-2, 8px)" wrap>
              {state.categories.sort().map(cat => {
                const styles = state.getCategoryStyle(cat);
                return (
                  <Badge key={cat} style={{ backgroundColor: styles.bg, color: styles.text }} size="lg">{cat}</Badge>
                );
              })}
            </Row>
          </Stack>
        </Card>

        {state.selectedElement ? (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="lg" border radius="xl" style={{ animation: 'ggui-slideInUp 300ms ease-out' }}>
            <Row justify="between" align="start">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={2}>{state.selectedElement.name}</Heading>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.selectedElement.category}</Text>
              </Stack>
              <Box padding="var(--ggui-spacing-4, 16px)" borderRadius="var(--ggui-shape-radius-lg, 12px)" background={state.getCategoryStyle(state.selectedElement.category).bg}>
                <Heading level={1} color={state.getCategoryStyle(state.selectedElement.category).text}>{state.selectedElement.symbol}</Heading>
              </Box>
            </Row>
            <Divider margin="var(--ggui-spacing-6, 24px)" />
            <CardGrid columns={3} gap={24}>
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                <Text variant="bodyLarge" weight="bold">{state.selectedElement.atomicNumber}</Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                <Text variant="bodyLarge" weight="bold">{state.selectedElement.atomicWeight} u</Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Group / Period</Text>
                <Text variant="bodyLarge" weight="bold">Group {state.selectedElement.col}, Period {state.selectedElement.row}</Text>
              </Stack>
            </CardGrid>
          </Card>
        ) : (
          <Alert variant="info" title="No element selected">
            Select an element from the table to view its properties and atomic details.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

